export const getCompleteChallengeUrl = () => {
  return `/api/challenges/complete`;
};

export const completeChallenge = async (
  completeChallengeRequest: CompleteChallengeRequest,
  options?: RequestInit,
): Promise<CompleteChallengeResponse> => {
  return customFetch<CompleteChallengeResponse>(getCompleteChallengeUrl(), {
    ...options,
    method: "POST",
    headers: { "Content-Type": "application/json", ...options?.headers },
    body: JSON.stringify(completeChallengeRequest),
  });
};

export const getCompleteChallengeMutationOptions = <
  TError = ErrorType<unknown>,
  TContext = unknown,
>(options?: {
  mutation?: UseMutationOptions<
    Awaited<ReturnType<typeof completeChallenge>>,
    TError,
    { data: BodyType<CompleteChallengeRequest> },
    TContext
  >;
  request?: SecondParameter<typeof customFetch>;
}): UseMutationOptions<
  Awaited<ReturnType<typeof completeChallenge>>,
  TError,
  { data: BodyType<CompleteChallengeRequest> },
  TContext
> => {
  const mutationKey = ["completeChallenge"];
  const { mutation: mutationOptions, request: requestOptions } = options
    ? options.mutation &&
      "mutationKey" in options.mutation &&
      options.mutation.mutationKey
      ? options
      : { ...options, mutation: { ...options.mutation, mutationKey } }
    : { mutation: { mutationKey }, request: undefined };

  const mutationFn: MutationFunction<
    Awaited<ReturnType<typeof completeChallenge>>,
    { data: BodyType<CompleteChallengeRequest> }
  > = (props) => {
    const { data } = props ?? {};

    return completeChallenge(data, requestOptions);
  };

  return { mutationFn, ...mutationOptions };
};

